	result := make([]interface{}, 0, len(networkInterfaces))
	for _, ni := range networkInterfaces {
		b, err := json.Marshal(ni)
		if err != nil {
			return nil, err
		}
		var m map[string]interface{}
		if err := json.Unmarshal(b, &m); err != nil {
			return nil, err
		}
		result = append(result, m)
	}
